// 팝업
//-------------------------------------------------------------------------------------------------------
scwin.f_PopUp = function(disGubun, chgGubun) {

    let rtnList = new Array();

    switch (disGubun) {
        case 1: //거래처 팝업(Customer)
            rtnList = udc_ilcomCode_pchsClnt.ilCommonPopUp(
                        scwin.udc_ilcomCode_pchsClnt_callBackFunc //pCallback
                      , cnd_ed_pchsClntNo.getValue().trim()
                      , cnd_txt_pchsClntNm.getValue() //pName
                      , chgGubun //pWinCloseTF
                      , '5'//pDispCnt
                      , 'Customer' //pTitle
                      , '140,300'   //pWidth
                      , null        //pHidden
                      , null        //pWhere
                      , '500'       //pW
                      , '500'       //pH
                      , null        //pTop
                      , null        //pLeft
                      , null        //pExistTF
                      , 'F'         //pAllSearchTF
                      , 'Customer Search,Customer Code,Customer Name'   //pWtitleSearch
                      //pNoDataCloseTF
                      //tmpDataSet
                    );
            break;

        case 2: //거래처 담당자 팝업(PIC) udc_ilcomCode_ed_pchsPicNo       
            var pParam = ed_pchsClntNo.getValue().trim();
            if (pParam == "") {
				$c.gus.cfAlertMsg(MSG_CM_ERR_056, new Array("Customer")); // 선택된 @이(가) 없습니다.
				ed_pchsClntNo.focus();
				return;
			}

            udc_ilcomCode_ed_pchsPicNo.setSelectId("retrieveClntPicInfo");      //retrieveClntPicInfo
            rtnList = udc_ilcomCode_ed_pchsPicNo.ilCommonPopUp(
                          scwin.udc_ilcomCode_ed_pchsPicNo_callBackFunc
                        , ed_pchsPicNo.getValue().trim()    // 화면에서의 ??? Code Element의	Value
			            , txt_pchsPicNm.getValue()          // 화면에서의 ??? Name Element의	Value
                        , chgGubun                          // 결과가 1건 일때  원도우를	AutoClose 여부	(T:CloseF:Opened)
                        , '4'                               // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                        , "PIC"                             // Title순서
                        , '100,350'                          // 보여주는 각 컬럼들의 폭
                        , null                              // 컬럼중에서 숨기는	컬럼 지정
                        , pParam                            // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                        , '500'                             // POP-UP뛰을때 원도우의	사용자 정의	폭
                        , '500'                             // POP-UP뛰을때 우도우의	사용자 정의	높이
                        , null                              // 윈도우 위치 Y좌표
                        , null                              // 윈도우 위치 X좌표
                        , null                              // 중복체크여부	("F")
                        , "T"                               // 전체검색허용여부	("F")
                        , null
                    );

            break;

        case 3: //검색 부서 코드 udc_ilcomCode_dept
            trnList = udc_ilcomCode_dept.ilCommonPopUp(
                          scwin.udc_ilcomCode_dept_callBackFunc
                        , cnd_ed_dept.getValue().trim() //pCode
                        , cnd_txt_deptnm.getValue()     //pName
                        , "T"                           //pWinCloseTF
                        , '2'                           //pDispCnt
                        , "Code, Name"                  //pTitle
                        , '80,230'                      //pWidth
                        , "3,4,5,6,7,8,9,10"            //pHidden
                        , null                          //pWhere
                        , null                          //pW
                        , null                          //pH
                        , null                          //pTop
                        , null                          //pLeft
                        , null                          //pExistTF
                        , "F"                           //pAllSearchTF
                        , "Department,Code,Name"        //pWtitleSearch
                        , "F"                           //pNoDataCloseTF
                        //tmpDataSet
                    );


            break;

        case 4: // 부서 코드(회계 부서 코드)
            let pCode = ed_dept.getValue();
			let pName = "";

            trnList = hid_udc_ed_dept.ilCommonPopUp(
                          scwin.hid_udc_ed_dept_callBackFunc    //pCallback
                        , pCode                                 //pCode
                        , pName                                 //pName
                        , "T"                                   //pWinCloseTF 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
                        , '2'                                   //pDispCnt 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
                        , "Code, Name"                          //pTitle Tit1le순서
                        , '80,230'                              //pWidth 보여주는	각 컬럼들의	폭
                        , "3,4,5,6,7,8,9,10"                    //pHidden 컬럼중에서 숨기는	컬럼 지정
                        , ''                                    //pWhere SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                        , null                                  //pW POP-UP뛰을때	원도우의	사용자 정의	폭
                        , null                                  //pH POP-UP뛰을때	우도우의	사용자 정의	높이
                        , null                                  //pTop 윈도우 위치 Y좌표
                        , null                                  //pLeft 윈도우 위치 X좌표
                        , null                                  //pExistTF 중복체크여부	("F")
                        , "F"                                   //pAllSearchTF 전체검색허용여부	("F")
                        , "귀속부서,Code,Name"                  //pWtitleSearch POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                        , "T"                                   //pNoDataCloseTF Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
                        , null//tmpDataSet
                    );
            break;
        default:
			break;
    }
}

